// Try to find Netflix tabs via Chrome tabs API
if (typeof chrome !== 'undefined' && chrome.tabs) {
  chrome.tabs.query({}, function(tabs) {
    const netflixTabs = tabs.filter(t => t.url && t.url.includes('netflix.com'));
    console.log('Netflix tabs:', JSON.stringify(netflixTabs.map(t => ({id: t.id, url: t.url, title: t.title, active: t.active, windowId: t.windowId}))));
  });
} else {
  console.log('chrome.tabs not available');
}
